def check_indices():
    s44 = stabilizers[44]
    s129 = stabilizers[129]
    print(f"Stabilizer 44: {s44}")
    print(f"Indices 44: {[i for i, c in enumerate(s44) if c != 'I']}")
    print(f"Stabilizer 129: {s129}")
    print(f"Indices 129: {[i for i, c in enumerate(s129) if c != 'I']}")

if __name__ == "__main__":
    check_indices()
